CustomField.formula:
IF(
    ISPICKVAL(Contract_Fee_Type__c, "Weekly Fee"),
    ROUND(((tc9_pr__Assignment_End_Date__c - tc9_pr__Assignment_Start_Date__c) + 1) / 7, 2),
    IF(
        ISPICKVAL(Contract_Fee_Type__c, "Monthly Fee"),
  /*      FLOOR((tc9_pr__Assignment_End_Date__c - tc9_pr__Assignment_Start_Date__c )/30.4375) + (MONTH(tc9_pr__Assignment_End_Date__c) - MONTH(tc9_pr__Assignment_Start_Date__c))/12.0, */
  ROUND((tc9_pr__Assignment_End_Date__c -  tc9_pr__Assignment_Start_Date__c )/30.4375 + (MONTH(tc9_pr__Assignment_End_Date__c) - MONTH( tc9_pr__Assignment_Start_Date__c))/12.0, 2),
        0.00
    )
)
